UPDATE GOLD_HEDGE_STRATEGY_INSTANCE
SET STATUS = #{status,jdbcType=VARCHAR},
REMARK = #{reason,jdbcType=VARCHAR}
WHERE INSTANCE_ID = #{instanceId,jdbcType=VARCHAR}

mapper.select:
SELECT

FROM
GOLD_HEDGE_STRATEGY_INSTANCE sc

    AND sc.DEL_FLAG = '0'

        AND sc.INSTANCE_ID = #{instanceId,jdbcType=VARCHAR}


        AND sc.STRATEGY_ID = #{strategyId,jdbcType=VARCHAR}


        AND sc.SYMBOL_CONFIG_ID = #{symbolConfigId,jdbcType=VARCHAR}


        AND sc.TAG_CODE = #{tagCode,jdbcType=VARCHAR}


        AND sc.TRADER_NO = #{traderNo,jdbcType=VARCHAR}


        AND sc.STATUS = #{status,jdbcType=VARCHAR}


ORDER BY sc.CREATE_TIME DESC
